const newItems = [];

for (const item of items[0].json) {
     newItems.push(`- [${item.reason}] => ${item.subject.title} @ ${item.subject.url.replace('api.','').replace('/repos','')}`);
  }

return [{json: {reportMessage: `${newItems.join('\r\n')}`, hasNotifications: items[0].json.length > 0}}];

